/**
 * Platform detection utilities
 */
export function getPlatform() {
    switch (process.platform) {
        case 'darwin':
            return 'macos';
        case 'linux':
            return 'linux';
        case 'win32':
            return 'windows';
        default:
            return 'unknown';
    }
}//# sourceMappingURL=https://github.com/VSCodium/sourcemaps/releases/download/insider-61321a14c608c2762ac3ce37cba10265d2b94f4d/node_modules-@anthropic-ai-sandbox-runtime-dist-utils-platform.js.map